html:
{% set zhs = get_sales_invoice_print_context(doc.name) %}
{% set company = zhs.company %}
{% set document = zhs.document %}
{% set print_sign = zhs.print_sign %}
{% set company_address_name = frappe.db.get_value("Dynamic Link", {"link_doctype": "Company", "link_name": doc.company, "parenttype": "Address"}, "parent") %}
{% set company_address = company.address or (frappe.db.get_value("Address", company_address_name, "address_line1") if company_address_name else "") %}
{% set company_address_raw = (frappe.get_doc("Address", company_address_name).get_display() | replace("<br>", "\n")) if company_address_name else (company_address or "") %}
{% set company_address_parts = [] %}
{% for part in company_address_raw.split("\n") %}
	{% if part.strip().strip(",").strip() %}{% set _ = company_address_parts.append(part.strip().strip(",").strip()) %}{% endif %}
{% endfor %}
{% set company_address_full = company_address_parts | join("، ") %}
{% set posting_time_short = (doc.posting_time | string)[:8] if doc.posting_time else "" %}

<style>
	@page { margin: 2mm; }
	.zhs-thermal {
		width: 72mm;
		color: #000;
		font-size: 11px;
		line-height: 1.3;
		direction: rtl;
		text-align: right;
		font-family: "Segoe UI", Tahoma, sans-serif;
		margin: 0 auto;
		padding: 0;
	}
	.zhs-thermal * {
		box-sizing: border-box;
	}
	.zhs-center {
		text-align: center;
	}
	.zhs-rtl {
		direction: rtl;
		text-align: right;
		unicode-bidi: plaintext;
	}
	.zhs-ltr {
		direction: ltr;
		text-align: left;
		unicode-bidi: plaintext;
	}
	.zhs-line {
		border-top: 1px dashed #000;
		margin: 5px 0;
	}
	.zhs-row {
		display: flex;
		flex-direction: row;
		justify-content: space-between;
		gap: 5px;
		margin: 1px 0;
	}
	.zhs-items {
		width: 100%;
		border-collapse: collapse;
		direction: rtl;
		table-layout: fixed;
	}
	.zhs-items td,
	.zhs-items th {
		padding: 1px 1px;
		border-bottom: 1px dashed #999;
		vertical-align: middle;
	}
	.zhs-items th {
		font-size: 10px;
		border-bottom: 1px solid #000;
		font-weight: 700;
	}
	.zhs-col-item {
		width: auto;
		text-align: right;
	}
	.zhs-col-qty {
		width: 28px;
		font-size: 9px;
		font-weight: 700;
	}
	.zhs-col-total {
		width: 62px;
		font-size: 9px;
		font-weight: 700;
	}
	.zhs-num {
		text-align: left;
		white-space: nowrap;
		direction: ltr;
		unicode-bidi: isolate;
	}
	.zhs-row .zhs-num {
		text-align: right;
	}
	.zhs-qr img {
		width: 200px;
		height: 200px;
	}
	.zhs-item-name {
		font-size: 11px;
		font-weight: 700;
		direction: rtl;
		text-align: right;
		unicode-bidi: plaintext;
		word-wrap: break-word;
		overflow-wrap: break-word;
		line-height: 1.2;
		white-space: pre-line;
	}
	.zhs-cust-block {
		text-align: right;
		direction: rtl;
	}
	.zhs-cust-block div {
		margin: 1px 0;
	}
	.zhs-total-box {
		border: 1.5px solid #000;
		padding: 5px 6px;
		margin: 5px 0;
	}
	.zhs-grand {
		font-size: 14px;
	}
	.zhs-vat-note {
		font-size: 9.5px;
		text-align: center;
		margin-top: 3px;
	}
	.zhs-thanks {
		font-size: 12px;
		font-weight: 700;
		margin-top: 5px;
	}
	.zhs-head-name {
		font-size: 13px;
		font-weight: 700;
	}
	.zhs-doc-title {
		font-size: 12px;
		font-weight: 700;
	}
	.zhs-seller-address {
		font-size: 9.5px;
		line-height: 1.35;
		margin-top: 2px;
	}
	.zhs-logo {
		max-width: 45mm;
		max-height: 22mm;
		margin: 0 auto 4px;
		display: block;
	}

	.zhs-addon-item {
		font-size: 9.5px !important;
		font-weight: 400 !important;
		color: #555 !important;
	}
	.zhs-addon-indent {
		padding-right: 12px !important;
	}
	.zhs-print-addon-desc {
		font-size: 9px !important;
		font-weight: 400 !important;
		color: #555 !important;
		margin-top: 1px;
		line-height: 1.25;
	}
</style>

<div class="zhs-thermal">
	<div class="zhs-center">
		{% if company.company_logo %}
			<img class="zhs-logo" src="{{ company.company_logo }}">
		{% endif %}
		<div class="zhs-head-name">{{ company.company_name }}</div>
		<div>الرقم الضريبي: {{ company.tax_id or "" }}</div>
		<div>السجل التجاري: {{ company.registration_details or "" }}</div>
		{% if company_address_full %}
			<div class="zhs-seller-address" dir="auto">{{ company_address_full }}</div>
		{% endif %}
	</div>

	<div class="zhs-line"></div>
	<div class="zhs-rtl">
		<div class="zhs-doc-title zhs-center">{{ document.title_ar }} / {{ document.title_en }}</div>
		<div><b>رقم الفاتورة:</b> <span class="zhs-ltr" style="display:inline-block">{{ doc.name }}</span></div>
		<div><b>التاريخ:</b> <span class="zhs-ltr" style="display:inline-block">{{ frappe.utils.format_date(doc.posting_date) }} {{ posting_time_short }}</span></div>
		{% set pos_profile = frappe.get_doc("POS Profile", doc.pos_profile) if doc.pos_profile else None %}
		{% if pos_profile and pos_profile.hspos_enable_order_number and doc.hspos_order_no %}
			<div><b>نوع ورقم الطلب:</b> <span style="font-weight: bold; font-size: 13px;">{{ _(doc.hspos_order_type or "Dine-in") }} #{{ "%02d" | format(doc.hspos_order_no | int) }}</span></div>
		{% endif %}
	</div>

	{% if doc.is_return or doc.is_debit_note %}
		<div class="zhs-line"></div>
		<div class="zhs-center">الفاتورة الأصلية: <span class="zhs-ltr">{{ zhs.reference_invoice or "غير محددة" }}</span></div>
		<div class="zhs-center">السبب: {{ zhs.note_reason }}</div>
	{% endif %}

	<div class="zhs-line"></div>
	<div class="zhs-cust-block">
		<div dir="auto"><b>العميل:</b> {{ doc.customer_name or doc.customer }}</div>
		{% if zhs.buyer_tax_id %}
			<div><b>الرقم الضريبي:</b> <span class="zhs-ltr" style="display:inline-block">{{ zhs.buyer_vat_label }}</span></div>
		{% endif %}
		{% if zhs.buyer_tax_id and zhs.buyer_address_lines %}
			<div dir="auto"><b>عنوان المشتري:</b> {{ zhs.buyer_address_lines | join("، ") }}</div>
		{% endif %}
	</div>

	<div class="zhs-line"></div>
	<table class="zhs-items">
		<thead>
			<tr>
				<th class="zhs-col-item">الصنف</th>
				<th class="zhs-col-qty zhs-num">الكمية</th>
				<th class="zhs-col-total zhs-num">الإجمالي</th>
			</tr>
		</thead>
		<tbody>
			{% for item in zhs.print_items %}
				<tr>
					<td class="zhs-col-item">
						<span class="zhs-item-name" dir="auto">{{ item.item_name }}</span>
						{% if item.hspos_addons_desc %}
							<div class="zhs-print-addon-desc" dir="auto">{{ item.hspos_addons_desc }}</div>
						{% endif %}
					</td>
					<td class="zhs-col-qty zhs-num">{{ item.qty }}</td>
					<td class="zhs-col-total zhs-num">{{ frappe.format_value((item.taxable_amount + item.vat_amount) * print_sign, {"fieldtype": "Currency", "options": doc.currency, "precision": 2}) }}</td>
				</tr>
			{% endfor %}
		</tbody>
	</table>

	<div style="margin-top:5px"></div>
	{% if zhs.discount_amount %}
		<div class="zhs-row">
			<span>الإجمالي قبل الخصم</span>
			<span class="zhs-num">{{ frappe.format_value(zhs.subtotal_before_discount * print_sign, {"fieldtype": "Currency", "options": doc.currency, "precision": 2}) }}</span>
		</div>
		<div class="zhs-row">
			<span>الخصم</span>
			<span class="zhs-num">{{ frappe.format_value(zhs.discount_amount * print_sign, {"fieldtype": "Currency", "options": doc.currency, "precision": 2}) }}</span>
		</div>
		<div class="zhs-row">
			<span>الإجمالي قبل الضريبة</span>
			<span class="zhs-num">{{ frappe.format_value((doc.net_total or 0) * print_sign, {"fieldtype": "Currency", "options": doc.currency, "precision": 2}) }}</span>
		</div>
	{% else %}
		<div class="zhs-row">
			<span>الإجمالي الخاضع للضريبة</span>
			<span class="zhs-num">{{ frappe.format_value((doc.net_total or 0) * print_sign, {"fieldtype": "Currency", "options": doc.currency, "precision": 2}) }}</span>
		</div>
	{% endif %}
	<div class="zhs-row">
		<span>ضريبة القيمة المضافة (15%)</span>
		<span class="zhs-num">{{ frappe.format_value((doc.total_taxes_and_charges or 0) * print_sign, {"fieldtype": "Currency", "options": doc.currency, "precision": 2}) }}</span>
	</div>

	<div class="zhs-total-box">
		<div class="zhs-row zhs-grand">
			<b>الإجمالي شامل الضريبة</b>
			<b class="zhs-num">{{ frappe.format_value((doc.grand_total or 0) * print_sign, {"fieldtype": "Currency", "options": doc.currency, "precision": 2}) }}</b>
		</div>
	</div>

	{% if zhs.prepaid_amount %}
		<div class="zhs-row">
			<span>المدفوع مقدماً</span>
			<span class="zhs-num">{{ frappe.format_value(zhs.prepaid_amount * print_sign, {"fieldtype": "Currency", "options": doc.currency}) }}</span>
		</div>
		<div class="zhs-row">
			<b>المبلغ المستحق</b>
			<b class="zhs-num">{{ frappe.format_value(zhs.payable_after_prepayment * print_sign, {"fieldtype": "Currency", "options": doc.currency}) }}</b>
		</div>
	{% endif %}

	<div class="zhs-vat-note">جميع الأسعار تشمل ضريبة القيمة المضافة</div>

	<div class="zhs-line"></div>
	<div class="zhs-center zhs-qr">
		{% if zhs.qr_image_src %}
			<img src="{{ zhs.qr_image_src }}">
		{% endif %}
	</div>

	<div class="zhs-center zhs-thanks">شكراً لزيارتكم / Thank you</div>
</div>

{% set stats = doc.get_print_stats() %}
{% set company = frappe.get_doc("Company", doc.company) %}
{% set currency = frappe.db.get_value("Company", doc.company, "default_currency") %}

<style>
	@page { margin: 2mm; }
	.cs-thermal {
		width: 72mm;
		color: #000;
		font-size: 11px;
		line-height: 1.35;
		direction: rtl;
		text-align: right;
		font-family: "Segoe UI", Tahoma, sans-serif;
		margin: 0 auto;
		padding: 0;
	}
	.cs-thermal * {
		box-sizing: border-box;
	}
	.cs-center {
		text-align: center;
	}
	.cs-line {
		border-top: 1px dashed #000;
		margin: 6px 0;
	}
	.cs-row {
		display: flex;
		flex-direction: row;
		justify-content: space-between;
		gap: 5px;
		margin: 2px 0;
	}
	.cs-title {
		font-size: 13px;
		font-weight: bold;
		margin: 5px 0;
	}
	.cs-section-title {
		font-weight: bold;
		font-size: 11px;
		margin: 8px 0 4px 0;
		border-bottom: 1px solid #000;
		padding-bottom: 2px;
	}
	.cs-table {
		width: 100%;
		border-collapse: collapse;
		margin-bottom: 5px;
		font-size: 10px;
	}
	.cs-table th, .cs-table td {
		padding: 2.5px 2px;
		text-align: right;
		vertical-align: middle;
	}
	.cs-table th {
		border-bottom: 1px solid #000;
		font-weight: bold;
	}
	.cs-table td {
		border-bottom: 1px dashed #ddd;
	}
	.cs-num {
		text-align: left !important;
		white-space: nowrap;
		direction: ltr;
