<div class="cs-thermal">
	<div class="cs-center">
		{% if company.company_logo %}
			<img class="cs-logo" src="{{ company.company_logo }}">
		{% endif %}
		<div class="cs-bold" style="font-size: 13px;">{{ company.company_name }}</div>
		<div class="cs-title">تقرير إغلاق الوردية المالي<br>Shift Closing Financial Report</div>
	</div>

	<div class="cs-line"></div>

	<div class="cs-meta">
		<div class="cs-row">
			<span>رقم الإغلاق / Closing Ref:</span>
			<span class="cs-num cs-bold">{{ doc.name }}</span>
		</div>
		<div class="cs-row">
			<span>أمين الصندوق / Cashier:</span>
			<span>{{ doc.user }}</span>
		</div>
		<div class="cs-row">
			<span>الوردية / Shift:</span>
			<span class="cs-num">{{ doc.hspos_opening_shift }}</span>
		</div>
		<div class="cs-row">
			<span>نقطة البيع / POS Profile:</span>
			<span>{{ doc.pos_profile }}</span>
		</div>
		<div class="cs-row">
			<span>تاريخ الإغلاق / Closed At:</span>
			<span class="cs-num">{{ frappe.utils.format_datetime(doc.period_end_date) }}</span>
		</div>
	</div>

	<div class="cs-line"></div>

	<div class="cs-section-title">ملخص الوردية / Shift Summary</div>
	<div class="cs-row">
		<span>إجمالي المبيعات / Total Sales:</span>
		<span class="cs-num cs-bold">{{ frappe.format_value(doc.grand_total, {"fieldtype": "Currency", "options": currency}) }}</span>
	</div>
	<div class="cs-row">
		<span>الكمية الإجمالية / Total Qty:</span>
		<span class="cs-num">{{ doc.total_quantity }}</span>
	</div>
	<div class="cs-row">
		<span>عدد الفواتير / Invoices Count:</span>
		<span class="cs-num">{{ doc.pos_transactions | length }}</span>
	</div>
	<div class="cs-row">
		<span>متوسط قيمة الفاتورة / Avg Ticket:</span>
		<span class="cs-num">{{ frappe.format_value(stats.average_ticket or 0, {"fieldtype": "Currency", "options": currency}) }}</span>
	</div>

	<div class="cs-line"></div>

	<div class="cs-section-title">طرق الدفع / Payments Summary</div>
	<table class="cs-table">
		<thead>
			<tr>
				<th>طريقة الدفع</th>
				<th class="cs-num">الافتتاحي</th>
				<th class="cs-num">المتوقع</th>
				<th class="cs-num">الفرق</th>
			</tr>
		</thead>
		<tbody>
			{% for item in doc.payment_reconciliation %}
				<tr>
					<td>{{ _(item.mode_of_payment) }}</td>
					<td class="cs-num">{{ frappe.format_value(item.opening_amount, {"fieldtype": "Currency", "options": currency}) }}</td>
					<td class="cs-num cs-bold">{{ frappe.format_value(item.expected_amount, {"fieldtype": "Currency", "options": currency}) }}</td>
					<td class="cs-num {% if item.difference < 0 %}cs-text-error{% elif item.difference > 0 %}cs-text-success{% endif %}">
						{{ frappe.format_value(item.difference, {"fieldtype": "Currency", "options": currency}) }}
					</td>
				</tr>
			{% endfor %}
		</tbody>
	</table>

	<div class="cs-line"></div>
	<div class="cs-footer">
		طُبع بواسطة نظام HIGHSPEED IT POS
	</div>
</div>
